namespace sv_a87c203ed9c543509e9e510a73a0d3fd;

public enum ThemeMode
{
    Light,
    Dark,
    System
}

public record ThemeInfo(ThemeMode Mode = ThemeMode.Light, string AccentColor = "#0d6efd");

@* 
    Reads theme via [CascadingParameter] — works even in the static
    layout because CascadingValueSource<T> crosses render-mode boundaries.
*@

<span class="theme-indicator" title="Current theme">
    @ThemeIcon @Theme.Mode
    <span class="accent-swatch"
          style="background-color: @Theme.AccentColor; width: 12px; height: 12px; display: inline-block; border-radius: 50%; vertical-align: middle; margin-left: 4px;">
    </span>
</span>

@code {
    [CascadingParameter]
    private ThemeInfo Theme { get; set; } = new();

    private string ThemeIcon => Theme.Mode switch
    {
        ThemeMode.Dark   => "🌙",
        ThemeMode.System => "💻",
        _                => "☀️"
    };
}

@page "/settings"
@rendermode InteractiveServer
@inject CascadingValueSource<ThemeInfo> ThemeSource

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="mb-3">
    <label class="form-label"><strong>Theme</strong></label>
    <div>
        @foreach (var mode in Enum.GetValues<ThemeMode>())
        {
            <label class="me-3">
                <input type="radio"
                       name="theme"
                       value="@mode"
                       checked="@(currentMode == mode)"
                       @onchange="() => SetMode(mode)" />
                @mode
            </label>
        }
    </div>
</div>

<div class="mb-3">
    <label class="form-label"><strong>Accent Color</strong></label>
    <input type="color"
           value="@currentAccent"
           @onchange="SetAccent" />
</div>

@code {
    [CascadingParameter]
    private ThemeInfo Theme { get; set; } = new();

    private ThemeMode currentMode;
    private string currentAccent = "#0d6efd";

    protected override void OnParametersSet()
    {
        currentMode = Theme.Mode;
        currentAccent = Theme.AccentColor;
    }

    private async Task SetMode(ThemeMode mode)
    {
        currentMode = mode;
        await ThemeSource.NotifyChangedAsync(new ThemeInfo(currentMode, currentAccent));
    }

    private async Task SetAccent(ChangeEventArgs e)
    {
        currentAccent = e.Value?.ToString() ?? currentAccent;
        await ThemeSource.NotifyChangedAsync(new ThemeInfo(currentMode, currentAccent));
    }
}

